import numpy as np

def is_spd(A: list[list[float]]) -> bool:
    matrix = np.array(A, dtype=float)
    # Check if square
    if matrix.ndim != 2 or matrix.shape[0] != matrix.shape[1]:
        return False

    # Check symmetry: A must equal its transpose within a small tolerance
    if not np.allclose(matrix, matrix.T, atol=1e-9):
        return False

    # Check positive definiteness: all eigenvalues must be > 1e-9
    try:
        eigenvalues = np.linalg.eigvalsh(matrix)
        if np.all(eigenvalues > 1e-9):
            return True
    except np.linalg.LinAlgError:
        return False

    return False
